import React, { useState, useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getPackages, resetState } from "../../features/package/packageSlicer";
import { Button, Input, Card, Space, Tag, Typography } from "antd";
import {
  BiUser,
  BiEnvelope,
  BiPackage,
  BiCheckCircle,
  BiCreditCard,
} from "react-icons/bi";
import { AiOutlineArrowRight } from "react-icons/ai";

const { Title, Text } = Typography;

const PaymentForm = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [selectedPackage, setSelectedPackage] = useState(null);
  const [user, setUser] = useState(null);

  const dispatch = useDispatch();
  const { packages, loading, error } = useSelector((state) => state.package);

  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem("user"));
    if (storedUser) {
      setUser(storedUser);
      setName(storedUser.firstname || "");
      setEmail(storedUser.email || "");
    }
  }, []);

  useEffect(() => {
    dispatch(resetState());
    dispatch(getPackages());
  }, [dispatch]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (name.trim() && email.trim() && selectedPackage) {
      alert(
        `Initiating secure payment authorization for ${selectedPackage.name}`,
      );
    } else {
      alert("Verification incomplete. Please specify all parameters.");
    }
  };

  return (
    <div className="min-h-screen bg-[#f7f7f8] p-8 flex justify-center items-center font-sans">
      <Card className="enterprise-card bg-white p-8 max-w-4xl w-full shadow-sm border-none">
        <div className="text-center mb-10">
          <Tag
            color="blue"
            className="rounded-full px-4 py-1 font-black uppercase tracking-widest text-[10px] mb-4 border-none bg-blue-50 text-blue-600"
          >
            Secure Provisioning
          </Tag>
          <h1 className="text-4xl font-black text-gray-900 tracking-tight">
            Access Tier Selection
          </h1>
          <p className="text-gray-500 font-medium tracking-tight mt-2 italic">
            Authorize system credentials via secure financial scaling
          </p>
        </div>

        {error && (
          <div className="mb-8 p-4 bg-red-50 rounded-2xl border border-red-100 text-center">
            <p className="text-red-600 font-bold uppercase tracking-tight text-xs">
              Registry Error:{" "}
              {typeof error === "string"
                ? error
                : error?.message || "Action Failed"}
            </p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-10">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Identity Capture */}
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  Client Identity
                </label>
                <Input
                  size="large"
                  prefix={<BiUser className="text-gray-300" />}
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Enter full name"
                  className="rounded-xl border-gray-100 h-12"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  Communication Node
                </label>
                <Input
                  size="large"
                  prefix={<BiEnvelope className="text-gray-300" />}
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="Enter email address"
                  className="rounded-xl border-gray-100 h-12"
                />
              </div>
            </div>

            {/* Selection Guidance */}
            <div className="bg-gray-50 rounded-3xl p-6 border border-gray-100 flex flex-col justify-center">
              <div className="flex items-start gap-4 mb-4">
                <BiCheckCircle className="text-blue-600 shrink-0" size={24} />
                <p className="text-xs text-gray-600 font-medium leading-relaxed">
                  Select a provisioned access tier to scale your operational
                  footprint and unlock advanced logistics nodes.
                </p>
              </div>
              <div className="flex items-start gap-4">
                <BiCreditCard className="text-blue-600 shrink-0" size={24} />
                <p className="text-xs text-gray-600 font-medium leading-relaxed">
                  Transactions are processed through encrypted financial
                  gateways ensuring absolute data integrity.
                </p>
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
              Available Provisioning Tiers
            </label>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {packages.map((pkg) => (
                <div
                  key={pkg._id}
                  onClick={() => setSelectedPackage(pkg)}
                  className={`relative p-6 rounded-2xl border-2 transition-all cursor-pointer group flex flex-col justify-between h-48 ${
                    selectedPackage?._id === pkg._id
                      ? "border-blue-600 bg-blue-50/50 shadow-md"
                      : "border-gray-100 hover:border-gray-300 bg-white"
                  }`}
                >
                  {selectedPackage?._id === pkg._id && (
                    <BiCheckCircle
                      className="absolute top-4 right-4 text-blue-600"
                      size={20}
                    />
                  )}
                  <div className="space-y-2">
                    <BiPackage
                      className={
                        selectedPackage?._id === pkg._id
                          ? "text-blue-600"
                          : "text-gray-300"
                      }
                      size={28}
                    />
                    <h4 className="font-black text-gray-900 tracking-tight uppercase text-sm line-clamp-1">
                      {pkg.name}
                    </h4>
                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                      {pkg.duration} Month Protocol
                    </p>
                  </div>
                  <div className="pt-4 border-t border-gray-100/50">
                    <span className="text-xl font-black text-gray-900 tracking-tighter">
                      {pkg.amount.toLocaleString()}{" "}
                      <span className="text-[10px] text-gray-400 uppercase tracking-widest">
                        ETB
                      </span>
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <Button
            type="primary"
            size="large"
            htmlType="submit"
            icon={<AiOutlineArrowRight />}
            className="w-full bg-gray-900 h-16 rounded-2xl font-black uppercase tracking-widest text-xs flex items-center justify-center gap-2 mt-8 hover:bg-black border-none shadow-lg transition-all active:scale-[0.98]"
            loading={loading}
          >
            Authorize Financial Transaction
          </Button>
        </form>
      </Card>
    </div>
  );
};

export default PaymentForm;
